transformation.script:
const order = payload.order;
const visit = payload.visit;
const patient = payload.patient;

// ── Gender: Male/Female → M/F ─────────────────────────────────────────
const genderMap = { 'Male': 'M', 'Female': 'F', 'male': 'M', 'female': 'F', 'MALE': 'M', 'FEMALE': 'F' };
const gender = genderMap[visit.gender.name] || 'M';

// ── Title → titleId numeric mapping ──────────────────────────────────
// Confirm actual numeric IDs with Akhil team — update this map accordingly
const titleIdMap = {
  'Mr': 1, 'Mr.': 1,
  'Mrs': 2, 'Mrs.': 2,
  'Miss': 3,
  'Ms': 3, 'Ms.': 3,
  'Dr': 4, 'Dr.': 4,
  'Master': 5, 'Baby': 5
};
const titleId = titleIdMap[payload.patientTitle] || 1;

// ── Name splitting from fullName ──────────────────────────────────────
const nameParts = (patient.fullName || '').trim().split(/\s+/);
const firstName = nameParts[0] || '';
const lastName = nameParts.length > 1 ? nameParts[nameParts.length - 1] : '';
const middleName = nameParts.length > 2 ? nameParts.slice(1, -1).join(' ') : '';

// ── DOB: ISO format preferred, convert DD/MM/YYYY if needed ──────────
let dob = '';
if (payload.patientDOBISO && payload.patientDOBISO !== '') {
  dob = payload.patientDOBISO;
} else if (patient.dob && patient.dob !== '') {
  const parts = patient.dob.split('/');
  dob = parts[2] + '-' + parts[1] + '-' + parts[0];
}

// ── Build orderServiceDetails from labTests ───────────────────────────
// integrationServiceCode is set to our serviceCode here;
// the AKHIL_SERVICE_CODE lookup (configured below) translates it
// to the Akhil-assigned code before delivery.
const orderServiceDetails = (order.labTests || []).map(function(test) {
  return {
    integrationServiceCode: test.serviceCode,
    stat: '',
    remarks: ''
  };
});

// ── Build request body ────────────────────────────────────────────────
const body = {
  titleId: titleId,
  firstName: firstName,
  middleName: middleName,
  lastName: lastName,
  gender: gender,
  dob: dob,
  mobileNo: patient.phone || '',
  address: patient.address || '',
  locationSource: 'REPLACE_WITH_AKHIL_LOCATION_SOURCE',
  cityId: 0,
  stateId: 0,
  countryId: 0,
  integrationOrderId: String(order.orderId),
  integrationPatientId: patient.mrn.documentNumber,
  orderServiceDetails: orderServiceDetails
};

return body;

